import math

def unique_paths(m: int, n: int) -> int:
    # Must take exactly (m-1) down moves and (n-1) right moves
    # Total moves = m+n-2, choose m-1 of them to be down
    return math.comb(m + n - 2, m - 1)

function uniquePaths(m, n) {
    const dp = Array.from({length: m}, () => new Array(n).fill(1));
    for (let r = 1; r < m; r++) {
        for (let c = 1; c < n; c++) {
            dp[r][c] = dp[r - 1][c] + dp[r][c - 1];
        }
    }
    return dp[m - 1][n - 1];
}
